<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const valor=parseFloat(document.getElementById('aluguel-valor').value);const taxa=parseFloat(document.getElementById('aluguel-taxa').value);clearError();if(isNaN(valor)||isNaN(taxa)||valor<0||taxa<0){showError('Informe aluguel e reajuste com valores válidos.');return;}const aumento=valor*(taxa/100);const novo=valor+aumento;document.getElementById('aluguel-novo').textContent='R$ '+fmtBRL(novo);document.getElementById('aluguel-diferenca').textContent='R$ '+fmtBRL(aumento);document.getElementById('tool-detail').textContent='Reajuste percentual simples aplicado ao valor atual do aluguel.';showResult('tool-result');}function clearTool(){['aluguel-valor','aluguel-taxa'].forEach(id=>document.getElementById(id).value='');['aluguel-novo','aluguel-diferenca'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule o reajuste antes de copiar o resultado.');return;}copyToClipboard('Novo aluguel: '+document.getElementById('aluguel-novo').textContent,button);}
</script>
